     */
    @RequestMapping(value = "/fileRestoreMng.do")
    public ModelAndView fileRestoreMng(FileSyncMngDto dto) throws Exception {
        String url = "sia/web/fileSync/fileRestoreMng";

        Date d = new Date();
        Date fromDate = DateUtils.addDays(d, -7); // 기본 1주일
        Date toDate = DateUtils.addDays(d, -3); // 최대 3일
        SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd");

        if (StringUtils.isBlank(dto.getcFrmDate())) {
            dto.setcFrmDate(sdf.format(fromDate));
        }
        if (StringUtils.isBlank(dto.getcToDate())) {
            dto.setcToDate(sdf.format(toDate));
        }

        mv.addObject("prePram", dto);
        return success(url);
    }

    /**
     * 파일 복원 대상 목록 조회
     */
    @RequestMapping(value = "/selectRestoreSingoList.json")
    public ModelAndView selectRestoreSingoList(FileSyncMngDto dto, Model model) throws Exception {
        HashMap<String, Object> commandMap = new HashMap<>();
        if (dto.getNewPage() > 0) {
            commandMap.put("newPage", dto.getNewPage());
        }

        commandMap.put("viewPageCnt", 20);
        commonUtl.pageSetting(commandMap);

        dto.setStartRowNum(MapUtils.getInteger(commandMap, "startRowNum"));
        dto.setEndRowNum(MapUtils.getInteger(commandMap, "endRowNum"));
        dto.setNewPage(MapUtils.getInteger(commandMap, "newPage"));
        dto.setPageSize(MapUtils.getInteger(commandMap, "pageSize"));

        List<FileSyncMngVO> resultList = fileRestoreMngService.selectRestoreSingoList(dto);
        int resultCnt = fileRestoreMngService.selectRestoreSingoListCnt(dto);
        int totalFileCnt = fileRestoreMngService.selectRestoreSingoFileTotalCnt(dto);

        mv.addObject("param", dto);
        mv.addObject("resultList", resultList);
        mv.addObject("maxPage", resultCnt);
        mv.addObject("newPage", dto.getNewPage());
        mv.addObject("pageSize", dto.getPageSize());
        mv.addObject("totalFileCnt", totalFileCnt);

        return success();
    }

    /**
     * 일괄 파일 복원 처리
     */
    @RequestMapping(value = "/updateBulkFileRestore.do")
    @ResponseBody
    public Map<String, Object> updateBulkFileRestore(@RequestParam(value = "singoNos[]") List<Integer> singoNos, HttpServletRequest request) throws Exception {
        HttpSession session = request.getSession();
        String userId = (String) session.getAttribute("userId");

        try {
            return fileRestoreMngService.updateBulkFileRestore(singoNos, userId);
        } catch (Exception e) {
            Map<String, Object> errorMap = new HashMap<>();
            errorMap.put("success", false);
            errorMap.put("message", "처리 중 오류가 발생했습니다: " + e.getMessage());
            return errorMap;
        }
    }

    /**
     * 조회 결과 전체 파일 복원 처리
     */
    @RequestMapping(value = "/updateAllFileRestore.do")
    @ResponseBody
    public Map<String, Object> updateAllFileRestore(FileSyncMngDto dto, HttpServletRequest request) throws Exception {
        HttpSession session = request.getSession();
        String userId = (String) session.getAttribute("userId");

        try {
            return fileRestoreMngService.updateAllFileRestore(dto, userId);
        } catch (Exception e) {
            Map<String, Object> errorMap = new HashMap<>();
            errorMap.put("success", false);
            errorMap.put("message", "처리 중 오류가 발생했습니다: " + e.getMessage());
            return errorMap;
        }
    }
}

