                error: function() {
                    alert("서버 통신 중 오류가 발생했습니다.");
                }
            });
        }
    }

    function sethyphen(obj) {
        let rawVal = obj.value.replace(/-/g, '');
        if (rawVal.length > 4) obj.value = rawVal.slice(0, 4) + '-' + rawVal.slice(4);
        else obj.value = rawVal;
    }

    function fnRowClick() {
